{"path": "/home/gron/Desktop/agent-eval-scratch/task-tracker/public/index.html", "content": "<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>Task Tracker</title>
  <style>
    body { font-family: Arial, sans-serif; margin: 40px; }
    .task { margin-bottom: 10px; }
    .task.done { text-decoration: line-through; color: #888; }
    input[type="text"] { padding: 6px; font-size: 14px; }
    button { padding: 6px 12px; font-size: 14px; margin-right: 6px; }
  </style>
</head>
<body>
  <h1>Task Tracker</h1>
  <div id="tasks"></div>
  <input type="text" id="new-task" placeholder="New task">
  <button onclick="addTask()">Add</button>

  <script>
    async function fetchTasks() {
      const res = await fetch('/tasks');
      const tasks = await res.json();
      renderTasks(tasks);
    }

    function renderTasks(tasks) {
      const container = document.getElementById('tasks');
      container.innerHTML = '';
      tasks.forEach((task, index) => {
        const div = document.createElement('div');
        div.className = 'task' + (task.done ? ' done' : '');
        div.innerHTML = `<span>${task.title}</span> <button onclick="toggleTask(${index})">${task.done ? 'Undo' : 'Done'}</button> <button onclick="deleteTask(${index})">Delete</button>`;
        container.appendChild(div);
      });
    }

    function addTask() {
      const input = document.getElementById('new-task');
      const title = input.value.trim();
      if (title) {
        fetch('/tasks', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ title })
        }).then(() => {
          input.value = '';
          fetchTasks();
        });
      }
    }

    function toggleTask(index) {
      fetch(`/tasks/${index}`, {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ done: !tasks[index].done })
      }).then(() => fetchTasks());
    }

    function deleteTask(index) {
      fetch(`/tasks/${index}`, { method: 'DELETE' }).then(() => fetchTasks());
    }

    fetchTasks();
  </script>
</body>
</html>"}

