{"path": "/home/gron/Desktop/agent-eval-scratch/task-tracker/test.js", "content": "const request = require('supertest');
const app = require('./index');

describe('Task API', () => {
  let taskId;

  beforeEach(async () => {
    const res = await request(app).post('/tasks').send({ title: 'Test task' });
    taskId = res.body.id;
  });

  it('should create a task', async () => {
    const res = await request(app).post('/tasks').send({ title: 'Test task' });
    expect(res.status).toBe(201);
    expect(res.body.title).toBe('Test task');
  });

  it('should get all tasks', async () => {
    const res = await request(app).get('/tasks');
    expect(res.status).toBe(200);
    expect(res.body).toBeInstanceOf(Array);
  });

  it('should update a task', async () => {
    const res = await request(app).put(`/tasks/${taskId}`).send({ title: 'Updated task', done: true });
    expect(res.status).toBe(200);
    expect(res.body.title).toBe('Updated task');
    expect(res.body.done).toBe(true);
  });

  it('should delete a task', async () => {
    const res = await request(app).delete(`/tasks/${taskId}`);
    expect(res.status).toBe(204);
  });
});"}

