const express = require('express');
const bodyParser = require('body-parser');
const cors = require('cors');

const app = express();
app.use(cors());
app.use(bodyParser.json());

const sqlite3 = require('sqlite3').verbose();

const db = new sqlite3.Database(':memory:');

const tasks = [];

function isOverdue(task) {
  return task.due && new Date(task.due) < new Date();
}

app.get('/tasks', (req, res) => {
  db.all('SELECT * FROM tasks', [], (err, rows) => {
  if (err) {
    res.status(500).json({ error: err.message });
    return;
  }
  res.json(rows);
});
});

app.post('/tasks', (req, res) => {
  const task = req.body;
  db.run('INSERT INTO tasks (title, description, due) VALUES (?, ?, ?)', [task.title, task.description, task.due], function(err) {
  if (err) {
    res.status(500).json({ error: err.message });
    return;
  }
  res.status(201).json(task);
});
  res.status(201).json(task);
});

app.put('/tasks/:id', (req, res) => {
  const id = req.params.id;
  const task = req.body;
  db.run('UPDATE tasks SET title = ?, description = ?, due = ? WHERE id = ?', [task.title, task.description, task.due, id], function(err) {
  if (err) {
    res.status(500).json({ error: err.message });
    return;
  }
  res.json(task);
});
  res.json(task);
});

app.delete('/tasks/:id', (req, res) => {
  const id = req.params.id;
  db.run('DELETE FROM tasks WHERE id = ?', [id], function(err) {
  if (err) {
    res.status(500).json({ error: err.message });
    return;
  }
  res.status(204).send();
});
  res.status(204).send();
});

const PORT = 3000;

db.serialize(() => {
  db.run('CREATE TABLE IF NOT EXISTS tasks (id INTEGER PRIMARY KEY AUTOINCREMENT, title TEXT, description TEXT, due TEXT)');
});
app.listen(PORT, () => {
  console.log(`Server running on http://localhost:${PORT}`);
});

