{"path": "/home/gron/Desktop/agent-eval-scratch/task-tracker/public/index.html", "content": "<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>Task Tracker</title>
  <style>
    body { font-family: Arial, sans-serif; margin: 40px; }
    .task { margin-bottom: 10px; }
    .task.done { text-decoration: line-through; color: #888; }
    .task input[type="checkbox"] { margin-right: 10px; }
    .task input[type="text"] { width: 200px; }
    .task button { margin-left: 10px; }
  </style>
</head>
<body>
  <h1>Task Tracker</h1>
  <div id="tasks"></div>
  <form id="task-form">
    <input type="text" id="task-title" placeholder="Task title">
    <button type="submit">Add</button>
  </form>

  <script>
    const tasksDiv = document.getElementById('tasks');
    const taskForm = document.getElementById('task-form');
    const taskTitleInput = document.getElementById('task-title');

    function loadTasks() {
      fetch('/tasks')
        .then(res => res.json())
        .then(tasks => {
          tasksDiv.innerHTML = '';
          tasks.forEach((task, index) => {
            const taskDiv = document.createElement('div');
            taskDiv.className = 'task' + (task.done ? ' done' : '');
            taskDiv.innerHTML = `
              <input type="checkbox" ${task.done ? 'checked' : ''}>
              <span>${task.title}</span>
              <button onclick="deleteTask(${index})">Delete</button>
            `;
            tasksDiv.appendChild(taskDiv);
          });
        });
    }

    function addTask(title) {
      fetch('/tasks', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ title })
      });
    }

    function deleteTask(index) {
      fetch('/tasks/' + index, { method: 'DELETE' });
    }

    function toggleTaskDone(index) {
      fetch('/tasks/' + index, {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ done: !tasks[index].done })
      });
    }

    taskForm.addEventListener('submit', e => {
      e.preventDefault();
      const title = taskTitleInput.value.trim();
      if (title) {
        addTask(title);
        taskTitleInput.value = '';
        loadTasks();
      }
    });

    loadTasks();
  </script>
</body>
</html>"}

